VALUES
  ('disabled-6f0ba476-moex-00601', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-110-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '甲將已使用2年之汽車一部贈與乙，經乙允受，約定1星期後交付。次日， 某丙表示願以高於市價購買該車，甲同意並依讓與合意交付丙並辦妥過戶 程序。甲之責任為何？', '["給付遲延責任", "給付不能責任", "不完全給付責任", "不當得利責任"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:31+00:00", "source_pdf_sha1": "c8bd1ebd2b10", "answer_pdf_sha1": "80b472858aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00602', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-110-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '下列關於契約成立之敘述，何者錯誤？', '["要約交錯", "要約與意思實現", "要約與承諾達成一致", "要約與要約引誘達成一致"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:31+00:00", "source_pdf_sha1": "c8bd1ebd2b10", "answer_pdf_sha1": "80b472858aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00603', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-110-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '甲有一塊 A 地，由乙供給材料並在該地為其興建一棟 B 別墅，約定報酬 700 萬元。乙嗣於民國 97 年 1 月間完工交屋，甲於 102 年 2 月間發現該 屋為輻射鋼筋屋，旋對乙主張解除契約，乙則於102年3月向甲起訴請求 給付報酬，甲對此提出消滅時效之抗辯。下列敘述，何者正確？', '["甲對乙主張解除契約，洵屬有理", "甲對乙所請求之報酬，提出消滅時效抗辯，並無理由", "甲、乙之間仍成立承攬契約", "甲之契約解除權，自交屋後1年間不行使而消滅"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:31+00:00", "source_pdf_sha1": "c8bd1ebd2b10", "answer_pdf_sha1": "80b472858aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00604', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-110-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '乙偷甲之A腳踏車賣給丙，並以移轉所有權之意思交付於善意且無重大過 失之丙。下列敘述，何者正確？', '["丙善意取得A腳踏車之所有權，甲對丙不得主張任何權利", "甲自喪失占有之時起2年以內，得向丙請求回復A腳踏車", "乙與丙之買賣契約無效，丙無法善意取得A腳踏車所有權", "丙不得主張善意取得A腳踏車所有權，甲得向丙請求回復A腳踏車"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:31+00:00", "source_pdf_sha1": "c8bd1ebd2b10", "answer_pdf_sha1": "80b472858aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00605', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-110-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', 'A地為甲所有之情形下，下列敘述，何者錯誤？', '["乙以行使地上權之意思，無權占有A地之一部分，於符合時效取得之要 件時，得請求登記為其占有部分之地上權人", "乙於A地上擅自建造之B房屋，因係附合於A地，不生單獨的所有權", "甲得將A地上特定之一部分的土地讓與於丙", "A地上之樹木為A地之成分，不生單獨的所有權"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:31+00:00", "source_pdf_sha1": "c8bd1ebd2b10", "answer_pdf_sha1": "80b472858aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00606', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-110-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '甲、乙、丙三人分別共有A地，應有部分均等。下列敘述，何者錯誤？', '["甲得以其應有部分供其債權人設定抵押權", "乙以行使地上權之意思擅自長期占有A地時，得基於時效取得請求登記 為地上權人", "甲、乙同意，但丙反對時，甲、乙仍得將A地全部處分予丁", "A地受戊侵奪時，丙不得單獨請求丁返還A地予甲乙丙三人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:31+00:00", "source_pdf_sha1": "c8bd1ebd2b10", "answer_pdf_sha1": "80b472858aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00607', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-110-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '甲是 A 地之所有人，與乙雖無租賃關係，但卻提供 A 地為乙設定普通地 上權20年，讓乙在A地上建築房屋。20年期限屆滿後，乙仍繼續使用A 地，而甲不即表示反對之意思。下列敘述，何者正確？', '["乙之普通地上權視為不定期限，繼續存在", "乙之普通地上權於期限屆滿時，當然消滅", "乙之普通地上權變為租賃關係，繼續存在", "乙之普通地上權變為使用借貸之關係，繼續存在"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:31+00:00", "source_pdf_sha1": "c8bd1ebd2b10", "answer_pdf_sha1": "80b472858aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00608', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-110-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '甲公司為董事乙購買一部名車，作為乙的公務用車，由公司職員丙駕駛之。 有關該座車之占有狀態，下列敘述，何者正確？', '["甲為占有人，丙為占有輔助人", "乙為占有人，丙為占有輔助人", "甲為間接占有人，乙為直接占有人，丙為占有輔助人", "乙為間接占有人，甲為直接占有人，丙為占有輔助人"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:31+00:00", "source_pdf_sha1": "c8bd1ebd2b10", "answer_pdf_sha1": "80b472858aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00609', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-110-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '為擔保甲銀行對乙之新臺幣（下同）1,500萬元債權，乙以其所有價值1,000 萬元之A不動產供甲設定第一次序普通抵押權，第三人丙、丁分別以其各 自所有價值900萬元、800萬元之B不動產及C不動產供甲設定擔保金額 為 1,000 萬元、600 萬元之第一次序普通抵押權。乙屆期無法清償對甲之 債務時，下列敘述，何者正確？', '["甲應先實行其對A不動產之抵押權求償，有不足時始得再實行對B、C 不動產之抵押權", "甲得先同時實行對B、C不動產之抵押權，其就拍賣後所得價金優先分 配之金額為900萬元、600萬元", "甲得先同時實行對A、C不動產之抵押權，其就拍賣後所得價金優先分 配之金額為937萬5,000元、562萬5,000元", "甲得同時實行對A、B不動產之抵押權，其就拍賣後所得價金優先分配 之金額為各750萬元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:31+00:00", "source_pdf_sha1": "c8bd1ebd2b10", "answer_pdf_sha1": "80b472858aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00610', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-110-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '下列關於法院許可終止收養之敘述，何者錯誤？', '["養父母死亡後，養子女得聲請法院許可終止收養", "養子女未滿7歲者，由收養終止後為其法定代理人之人向法院聲請許可", "養子女為成年人者，其許可終止收養之聲請，應經其本生父母之同意", "法院認終止收養顯失公平者，得不許可之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:31+00:00", "source_pdf_sha1": "c8bd1ebd2b10", "answer_pdf_sha1": "80b472858aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL)
